UPDATE chat_tasks
SET status = 'DONE',
    completed_at = #{completedAt}
WHERE id = #{taskId}
  AND room_id = #{roomId}
  AND status = 'PENDING'

UPDATE chat_tasks
SET status = 'CONFIRMED',
    confirmed_at = #{confirmedAt}
WHERE id = #{taskId}
  AND room_id = #{roomId}
  AND status = 'DONE'
